// // This module compares two 4-bit numbers and outputs if they are not equal, less than, or greater than each other.
module comparator(
	input [3:0] a,
	input [3:0] b,
	output equal,
	output greater,
	output less);
assign equal = (a == b);
assign greater = (a > b);
assign less = (a < b);

endmodule
